      {
        "from": "gpt",
        "value": {
          "dialogue": "已确认！记录方案包括七列，每天观察一次，最多200行。请注意安全操作，戴手套、口罩，实验后洗手。",
          "next_action_type": "confirmation",
          "options": [],
          "hints": [],
          "phase_complete": true,
          "data_table_schema": {
            "columns": [
              { "key": "treatment", "title": "处理组", "type": "text", "required": true },
