              { "key": "mold_visible", "title": "是否发霉", "type": "text", "required": true },
              { "key": "mold_area", "title": "霉斑面积（平方厘米）", "type": "number", "required": true },
              { "key": "photo", "title": "霉菌照片", "type": "image", "required": false },
              { "key": "notes", "title": "备注", "type": "text", "required": false }
            ],
            "maxRows": 200
          }
        }
      }
    ]
  }
}

